CREATE OR REPLACE FUNCTION "public"."get_my_group_ids"() RETURNS SETOF "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select gm.group_id from group_memberships gm
  join status_definitions sd on sd.id = gm.status_id
  where gm.person_id = auth.uid()
    and sd.slug != 'expelled'
    and gm.ended_at is null
$$;


ALTER FUNCTION "public"."get_my_group_ids"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_my_org_ids"() RETURNS SETOF "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select get_my_group_ids()
$$;


ALTER FUNCTION "public"."get_my_org_ids"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_my_organization_ids"() RETURNS SETOF "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select om.org_id from org_memberships om
  join status_definitions sd on sd.id = om.status_id
  where om.person_id = auth.uid()
    and sd.slug != 'expelled'
    and om.ended_at is null
$$;


ALTER FUNCTION "public"."get_my_organization_ids"() OWNER TO "postgres";

