CREATE OR REPLACE VIEW "public"."current_system_role_holders" AS
 SELECT "pa"."group_id" AS "org_id",
    "spr"."slug" AS "system_role",
    "pa"."person_id",
    "p"."full_name",
    "pos"."title" AS "position_title"
   FROM ((("public"."position_assignments" "pa"
     JOIN "public"."positions" "pos" ON (("pos"."id" = "pa"."position_id")))
     JOIN "public"."system_position_roles" "spr" ON (("spr"."id" = "pos"."system_role_id")))
     JOIN "public"."persons" "p" ON (("p"."id" = "pa"."person_id")))
  WHERE ("pa"."term_end" IS NULL);


